const long long MOD = 1000000007LL;

long long modPow(long long a, long long e) {
    long long r = 1;
    while (e > 0) {
        if (e & 1) r = r * a % MOD;
        a = a * a % MOD;
        e >>= 1;
    }
    return r;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long n;
    cin >> n;
    long long ans = (modPow(10, n) - 2 * modPow(9, n) % MOD + modPow(8, n)) % MOD;
    if (ans < 0) ans += MOD;
    cout << ans << '\n';
    return 0;
}

