    vector<vector<int>> t(n, vector<int>(n));
    for (auto& row : t) for (int& x : row) cin >> x;
    vector<int> p;
    for (int i = 1; i < n; ++i) p.push_back(i);
    int ans = 0;
    do {
        int cost = 0, prev = 0;
