#include <string>
#include <tuple>
#include <utility>
#include <vector>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;
    vector<vector<int>> graph(n);
    for (int i = 0; i < m; ++i) {
        int a, b;
        cin >> a >> b;
        --a; --b;
        graph[a].push_back(b);
    }
    long long ans = 0;
    for (int s = 0; s < n; ++s) {
        vector<int> seen(n, 0);
        queue<int> q;
        seen[s] = 1;
        q.push(s);
        while (!q.empty()) {
            int v = q.front();
            q.pop();
            ++ans;
            for (int to : graph[v]) {
                if (seen[to]) continue;
                seen[to] = 1;
                q.push(to);
            }
        }
    }
    cout << ans << '\n';
    return 0;
}
